    "                   fontsize=13, fontweight='bold', pad=15)\n",
    "axes[0].grid(axis='y', alpha=0.3, linestyle='--')\n",
    "axes[0].set_ylim(0, max(loss_epoch_0, loss_epoch_1) * 1.2)\n",
