    "    axes[0].annotate('', xy=(1, loss_epoch_1), xytext=(0, loss_epoch_0),\n",
    "                     arrowprops=dict(arrowstyle='->', lw=2, color='green'))\n",
    "    axes[0].text(0.5, (loss_epoch_0 + loss_epoch_1) / 2, \n",
    "                 f'←“ {reduccion_pct:.1f}%', \n",
    "                 ha='center', va='center', \n",
