    "axs[2].plot(ruido2, color='magenta'); axs[2].set_title('Paso 2 ($X_{t_2}$)')\n",
    "axs[3].plot(ruido3, color='gray'); axs[3].set_title('Paso final ($X_T$) - Puro Ruido')\n",
    "plt.suptitle(\"Forward Pass Conceptual de un Modelo de Difusión\")\n",
